import{_ as t,m as r,k as a,ah as n}from"./chunks/framework.BgQAHmMj.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"developers/getting-started/introduction.md","filePath":"src/en/developers/getting-started/introduction.md"}'),o={name:"developers/getting-started/introduction.md"};function i(s,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-creopse" tabindex="-1">What is Creopse? <a class="header-anchor" href="#what-is-creopse" aria-label="Permalink to &quot;What is Creopse?&quot;">​</a></h2><p><strong>Creopse</strong> is a hybrid and extensible CMS built around a <strong>Laravel</strong> or <strong>Adonis</strong> backend coupled with a <strong>Vue.js 3</strong> or <strong>React</strong> frontend via <strong>Inertia.js</strong>. It ships with both an integrated front-end for building interfaces quickly, and a REST API for delivering content to any external client.</p><h3 id="why-hybrid" tabindex="-1">Why &quot;hybrid&quot;? <a class="header-anchor" href="#why-hybrid" aria-label="Permalink to &quot;Why &quot;hybrid&quot;?&quot;">​</a></h3><p>Traditional CMS platforms (WordPress, Drupal) tightly couple rendering and data: the frontend and backend share the same process. Headless CMS platforms take the opposite approach: they drop the front-end entirely and expose only an API. Creopse takes the best of both:</p><ul><li>An <strong>integrated front-end</strong> to deploy a full website without a separate infrastructure.</li><li>A <strong>REST API</strong> to feed mobile applications, third-party integrations, or any decoupled client.</li></ul><h3 id="extensible-by-design" tabindex="-1">Extensible by design <a class="header-anchor" href="#extensible-by-design" aria-label="Permalink to &quot;Extensible by design&quot;">​</a></h3><p>Creopse is built on a plugin architecture: any new feature can be encapsulated, distributed, and installed independently, without touching the core system.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><h3 id="system-requirements" tabindex="-1">System requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System requirements&quot;">​</a></h3><p><strong>With a Laravel backend:</strong></p><ul><li><strong>Laravel</strong>: version 10, 11, or 12.</li><li><strong>PHP</strong>: <ul><li>Laravel 10: 8.1 minimum.</li><li>Laravel 11 &amp; 12: 8.2 minimum.</li></ul></li><li><strong>Composer</strong>: PHP dependency management.</li><li><strong>pnpm</strong>: frontend asset compilation and management.</li></ul><p><strong>With an Adonis backend:</strong> <em>(coming soon)</em></p><h3 id="recommended-knowledge" tabindex="-1">Recommended knowledge <a class="header-anchor" href="#recommended-knowledge" aria-label="Permalink to &quot;Recommended knowledge&quot;">​</a></h3><p>Creopse builds on existing tools — familiarity with the following concepts will ease the learning curve:</p><ul><li><strong>Laravel or Adonis</strong>: routing, middlewares, migrations, ORM.</li><li><strong>Inertia.js</strong>: the bridge between the backend and the frontend framework.</li><li><strong>Vue.js 3 or React</strong>: client-side rendering and state management.</li></ul><p>Reference documentation:</p><ul><li><a href="https://laravel.com/docs" target="_blank" rel="noreferrer">Laravel</a></li><li><a href="https://adonisjs.com" target="_blank" rel="noreferrer">Adonis</a></li><li><a href="https://inertiajs.com" target="_blank" rel="noreferrer">Inertia.js</a></li><li><a href="https://vuejs.org" target="_blank" rel="noreferrer">Vue.js 3</a></li><li><a href="https://react.dev" target="_blank" rel="noreferrer">React</a></li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./core-concepts.html">Core concepts</a>: the fundamentals of Creopse&#39;s architecture.</li><li><a href="./installation.html">Installation</a>: setting up the environment and getting started.</li></ul>',20)])])}const g=t(o,[["render",i]]);export{p as __pageData,g as default};
